#!/usr/bin/env python3
"""
deploy_v19_34_219.py - EXECUTION PILLAR: read trade_outcomes DIRECTLY (pymongo)

v217/218 derived live execution-state via learning_loop.get_recent_outcomes(),
but that reference returns EMPTY in the TQS-engine context (the learning loop's
collections are wired in a deferred background init), so the pillar fell back to
the all-default constant (76.50). PROVEN by probe_live_exec_state.py: a direct
pymongo read of trade_outcomes returns 30 fresh won/lost docs (win 0.48).

v219: the pillar now reads `trade_outcomes` DIRECTLY via a cached pymongo client
(same pattern as pnl_compute) and ALWAYS overrides recent_win_rate +
consecutive_losses + tilt from that live tape. learning_loop kept only as a
last-resort fallback. Emits a WARN if the direct read ever returns 0.

SAFETY: checksum-guarded full-file replace (writes ONLY if on-disk file matches
the v218 sha OR already carries the v219 marker; aborts on drift). Idempotent,
transactional, runs the test, commits + pushes BEFORE restart.

RUN ON THE DGX:
  curl -s https://paste.rs/XXXXX -o /tmp/deploy_v19_34_219.py
  python3 /tmp/deploy_v19_34_219.py
  ./start_backend.sh --force
"""
import os, base64, hashlib, shutil, subprocess, sys, py_compile

REPO = os.path.expanduser("~/Trading-and-Analysis-Platform")
if not os.path.isdir(REPO):
    REPO = os.getcwd()
SVC = os.path.join(REPO, "backend", "services", "tqs", "execution_quality.py")
TEST = os.path.join(REPO, "backend", "tests",
                    "test_v19_34_217_execution_pillar_live_state.py")

MARKER = "v19.34.219"
PREPATCH_SHA = "cf4bcb1e638d4659537202745d04f4543b5ef690c24e964639fa0cd3d2257847"
NEW_SVC_SHA = "3ef80696a59927207b6bcef3ce56ed2a4d78e28148da78141cef28c2934720dc"
SVC_B64 = ""
TEST_B64 = ""


def fail(m):
    print("\n[FAIL] " + m); sys.exit(1)


def main():
    print("== deploy_v19_34_219 ==\nrepo: " + REPO)
    if not os.path.isfile(SVC):
        fail("target not found: " + SVC)
    cur = open(SVC, "rb").read()
    cur_sha = hashlib.sha256(cur).hexdigest()
    new_bytes = base64.b64decode(SVC_B64)
    assert hashlib.sha256(new_bytes).hexdigest() == NEW_SVC_SHA, "payload corrupt"

    if MARKER in cur.decode("utf-8", "ignore"):
        print("[ok] already patched (v219 marker) - skipping file write.")
    elif cur_sha == PREPATCH_SHA:
        shutil.copy2(SVC, SVC + ".v219.bak")
        open(SVC, "wb").write(new_bytes)
        try:
            py_compile.compile(SVC, doraise=True)
        except py_compile.PyCompileError as e:
            shutil.copy2(SVC + ".v219.bak", SVC)
            fail("py_compile failed, rolled back: " + str(e))
        os.remove(SVC + ".v219.bak")
        print("[ok] execution_quality.py replaced + compiles clean.")
    else:
        fail("on-disk execution_quality.py matches NEITHER the v218 sha NOR the "
             "v219 marker (sha=" + cur_sha[:12] + "). Drift - aborting WITHOUT changes.")

    os.makedirs(os.path.dirname(TEST), exist_ok=True)
    open(TEST, "wb").write(base64.b64decode(TEST_B64))
    print("[ok] wrote test file")

    print("\n== pytest ==")
    r = subprocess.run([sys.executable, "-m", "pytest", TEST, "-q"],
                       cwd=os.path.join(REPO, "backend"))
    if r.returncode != 0:
        fail("pytest failed - NOT committing.")
    print("[ok] tests green.")

    print("\n== git commit + push ==")
    subprocess.run(["git", "add", "-A"], cwd=REPO)
    cm = subprocess.run(["git", "commit", "-m",
        "v19.34.219 Execution pillar: read trade_outcomes directly via pymongo "
        "(learning_loop returned empty in engine ctx); always override wr+streak"],
        cwd=REPO)
    if cm.returncode == 0:
        subprocess.run(["git", "push"], cwd=REPO)
        print("[ok] committed + pushed.")
    else:
        print("[info] nothing to commit - skipping push.")

    print("\n[DONE] Restart backend:  ./start_backend.sh --force")
    print("Then re-run:  python3 /tmp/diag_tqs_pillar_breakdown.py --since-min 15")
    print("EXECUTION recent_win_rate should move OFF 0.5 (100pct) and the pillar")
    print("should SPREAD. If still pinned, grep backend.log for 'v19.34.219 exec-pillar'.")


if __name__ == "__main__":
    main()
